module reg16(
    input               clk     , 
    input               rst     ,
    input               en      ,
    input       [15:0]  data_in ,

    output reg  [15:0]  data_out
);
  wire _tap_clk = clk & {1{1'b1}};


// Register operation
always @(posedge clk) begin
    if (rst) begin
        data_out <= 16'd0;
    end else if (en) begin
        data_out <= data_in;
    end
end

endmodule
